FOOD_BY_ID = {food["id"]: food for food in FOODS}

# alias lookup for simple demo recognition
ALIAS_TO_ID: dict[str, str] = {}
for food in FOODS:
    ALIAS_TO_ID[food["id"].lower()] = food["id"]
    ALIAS_TO_ID[food["name_en"].lower()] = food["id"]
    ALIAS_TO_ID[food["name_ar"].lower()] = food["id"]
    for alias in food["aliases"]:
        ALIAS_TO_ID[alias.lower()] = food["id"]


def get_food(food_id: str) -> Optional[FoodNutrition]:
    return FOOD_BY_ID.get(food_id)


def search_foods(query: str = "", limit: int = 50) -> list[FoodNutrition]:
    q = (query or "").strip().lower()
    if not q:
        return FOODS[:limit]
    out = []
    for food in FOODS:
        blob = " ".join([food["id"], food["name_en"], food["name_ar"], *food["aliases"], food["category"]]).lower()
        if q in blob:
            out.append(food)
    return out[:limit]


def categories_summary() -> list[dict]:
    counts: dict[str, int] = {}
    for food in FOODS:
        counts[food["category"]] = counts.get(food["category"], 0) + 1
    return [{"key": k, "count": v} for k, v in sorted(counts.items())]
